// ==UserScript==<br />
// @name        LIHKG App Url Replacer<br />
// @description app shared link redirect to <a href="http://na.cx" data-sr-url="https://r.lihkg.com/link?u=http%3A%2F%2Fna.cx&d=WBxgLKRbSoXNuYZPkEN3uGN6obqfy%2FNc7jg2IsrTbnE%3D&h=39233631" data-auto-link target="_blank">na.cx</a> (web)<br />
// @author	123321<br />
// @version 	1.3<br />
// @include 	<a href="http://lihkg.com/*" data-auto-link target="_blank">http://lihkg.com/*</a><br />
// @include 	<a href="https://lihkg.com/*" data-auto-link target="_blank">https://lihkg.com/*</a><br />
<br />
// @namespace 1<br />
// ==/UserScript==<br />
<br />
var url = location.href;<br />
<br />
if (location.href.search(&quot;.com&quot;)&gt;0){<br />
  url = url.replace(&quot;.com&quot;,&quot;.na.cx&quot;);<br />
  location.href=url;<br />
}<br />
<br />
